// resolvers.js
import { GraphQLError } from 'graphql';

const resolvers = {
  Query: {
    // Root query resolver
    user: async (_, { id }, { db, auth }) => {
      auth.requireAuth();
      const user = await db.users.findById(id);
      if (!user) throw new GraphQLError('User not found', { extensions: { code: 'NOT_FOUND' } });
      return user;
    },

    users: async (_, { role, pagination }, { db }) => {
      const { page = 1, limit = 10 } = pagination || {};
      const query = role ? { role } : {};
      const users = await db.users.find(query)
        .skip((page - 1) * limit)
        .limit(limit);
      return users;
    },

    posts: async (_, { tag, pagination }, { db }) => {
      const { page = 1, limit = 10 } = pagination || {};
      const query = tag ? { tags: tag } : {};
      const [posts, total] = await Promise.all([
        db.posts.find(query).skip((page - 1) * limit).limit(limit),
        db.posts.countDocuments(query)
      ]);
      return {
        posts,
        total,
        page,
        totalPages: Math.ceil(total / limit),
        hasNext: page * limit < total
      };
    }
  },

  // Field resolvers — called when field is requested
  User: {
    posts: async (parent, _, { db }) => {
      // parent = the User object
      return db.posts.find({ authorId: parent.id });
    }
  },

  Post: {
    author: async (parent, _, { db }) => {
      return db.users.findById(parent.authorId);
    },
    comments: async (parent, _, { db }) => {
      return db.comments.find({ postId: parent.id }).sort({ createdAt: -1 });
    }
  },

  Mutation: {
    createPost: async (_, { title, content }, { db, auth }) => {
      const user = auth.requireAuth();
      const post = await db.posts.create({
        title, content, authorId: user.id, published: false, tags: []
      });
      return post;
    },

    addComment: async (_, { postId, text }, { db, auth, pubsub }) => {
      const user = auth.requireAuth();
      const comment = await db.comments.create({
        text, postId, authorId: user.id, createdAt: new Date()
      });
      pubsub.publish(`COMMENT_ADDED_${postId}`, { commentAdded: comment });
      return comment;
    }
  }
};

export default resolvers;
