// Server setup with subscriptions
import { ApolloServer } from '@apollo/server';
import { WebSocketServer } from 'ws';
import { useServer } from 'graphql-ws/lib/use/ws';
import { PubSub } from 'graphql-subscriptions';
import { makeExecutableSchema } from '@graphql-tools/schema';

const pubsub = new PubSub();

const typeDefs = `
  type Subscription {
    messageSent(channelId: ID!): Message!
    userStatusChanged: User!
    notificationReceived: Notification!
  }

  type Message {
    id: ID!
    text: String!
    author: User!
    channelId: ID!
    createdAt: String!
  }

  type Notification {
    id: ID!
    type: String!
    message: String!
    read: Boolean!
  }
`;

const resolvers = {
  Subscription: {
    messageSent: {
      subscribe: (_, { channelId }) => {
        return pubsub.asyncIterator([`MESSAGE_SENT_${channelId}`]);
      },
      // Optional: filter events
      resolve: (payload) => payload.messageSent
    },

    userStatusChanged: {
      subscribe: () => pubsub.asyncIterator(['USER_STATUS_CHANGED'])
    },

    notificationReceived: {
      subscribe: (_, __, { auth }) => {
        const user = auth.requireAuth();
        return pubsub.asyncIterator([`NOTIFICATION_${user.id}`]);
      }
    }
  },

  Mutation: {
    sendMessage: async (_, { channelId, text }, { db, auth, pubsub }) => {
      const user = auth.requireAuth();
      const message = await db.messages.create({
        text, channelId, authorId: user.id, createdAt: new Date()
      });
      // Publish event to channel subscribers
      pubsub.publish(`MESSAGE_SENT_${channelId}`, { messageSent: message });
      return message;
    }
  }
};

// WebSocket server setup
const schema = makeExecutableSchema({ typeDefs, resolvers });
const wsServer = new WebSocketServer({ path: '/graphql' });
const serverCleanup = useServer({ schema, context: (ctx) => ({
  auth: createAuthContext(ctx.connectionParams?.token)
}) }, wsServer);

const apolloServer = new ApolloServer({
  schema,
  plugins: [
    ApolloServerPluginDrainHttpServer({ httpServer }),
    { async serverWillStart() {
      return { async drainServer() { await serverCleanup.dispose(); } };
    }}
  ]
});
