// Apollo Client setup
import { ApolloClient, InMemoryCache, gql, useQuery, useMutation, useLazyQuery } from '@apollo/client';
import { createHttpLink } from '@apollo/client/link/http';
import { setContext } from '@apollo/client/link/context';

const httpLink = createHttpLink({ uri: '/graphql' });

const authLink = setContext((_, { headers }) => ({
  headers: { ...headers, authorization: localStorage.getItem('token') ? `Bearer ${localStorage.getItem('token')}` : '' }
}));

const client = new ApolloClient({
  link: authLink.concat(httpLink),
  cache: new InMemoryCache({
    typePolicies: {
      Query: {
        fields: {
          posts: { keyArgs: ['tag'], merge: (existing, incoming) => ({
            ...incoming,
            posts: [...(existing?.posts || []), ...incoming.posts]
          })}
        }
      }
    }
  })
});

// Queries
const GET_POSTS = gql`
  query GetPosts($page: Int) {
    posts(pagination: { page: $page, limit: 20 }) {
      posts { id title content tags author { name } }
      total hasNext
    }
  }
`;

const CREATE_POST = gql`
  mutation CreatePost($title: String!, $content: String!) {
    createPost(title: $title, content: $content) {
      id title content
    }
  }
`;

function PostList() {
  const { loading, data, fetchMore } = useQuery(GET_POSTS, {
    variables: { page: 1 }
  });

  const [createPost] = useMutation(CREATE_POST, {
    // Optimistic update
    optimisticResponse: {
      createPost: { __typename: 'Post', id: 'temp-id', title: '', content: '' }
    },
    // Update cache after mutation
    update(cache, { data: { createPost: newPost } }) {
      cache.modify({
        fields: {
          posts(existingPosts = []) {
            const newRef = cache.writeFragment({
              data: newPost,
              fragment: gql`fragment NewPost on Post { id title content }`
            });
            return [newRef, ...existingPosts];
          }
        }
      });
    }
  });

  if (loading) return <p>Loading...</p>;

  return (
    <div>
      {data.posts.posts.map(post => <div key={post.id}>{post.title}</div>)}
      {data.posts.hasNext && (
        <button onClick={() => fetchMore({ variables: { page: data.posts.page + 1 } })}>
          Load More
        </button>
      )}
    </div>
  );
}
