// dataloaders.js
import DataLoader from 'dataloader';

// Batch function: receives array of IDs, returns array of results
export function createLoaders(db) {
  return {
    userLoader: new DataLoader(async (userIds) => {
      // One query instead of N
      const users = await db.users.find({ _id: { $in: userIds } });
      const userMap = new Map(users.map(u => [u.id.toString(), u]));
      // Return in same order as input keys
      return userIds.map(id => userMap.get(id.toString()) || null);
    }),

    postsByUserLoader: new DataLoader(async (userIds) => {
      const posts = await db.posts.find({ authorId: { $in: userIds } });
      const postsMap = new Map();
      for (const id of userIds) postsMap.set(id.toString(), []);
      for (const post of posts) {
        postsMap.get(post.authorId.toString()).push(post);
      }
      return userIds.map(id => postsMap.get(id.toString()) || []);
    }),

    commentsByPostLoader: new DataLoader(async (postIds) => {
      const comments = await db.comments.find({ postId: { $in: postIds } });
      const commentsMap = new Map();
      for (const id of postIds) commentsMap.set(id.toString(), []);
      for (const comment of comments) {
        commentsMap.get(comment.postId.toString()).push(comment);
      }
      return postIds.map(id => commentsMap.get(id.toString()) || []);
    })
  };
}

// Context setup — new loaders per request
const server = new ApolloServer({
  typeDefs,
  resolvers,
  context: ({ req }) => {
    const auth = createAuthContext(req.headers.authorization);
    const loaders = createLoaders(db); // fresh per request!
    return { auth, db, loaders };
  }
});

// Resolvers using DataLoaders
const resolvers = {
  Query: {
    users: async (_, __, { db }) => db.users.find({})
  },

  User: {
    // Uses batch loader instead of N individual queries
    posts: (parent, _, { loaders }) => {
      return loaders.postsByUserLoader.load(parent.id);
    }
  },

  Post: {
    author: (parent, _, { loaders }) => {
      return loaders.userLoader.load(parent.authorId);
    },
    comments: (parent, _, { loaders }) => {
      return loaders.commentsByPostLoader.load(parent.id);
    }
  },

  Comment: {
    author: (parent, _, { loaders }) => {
      return loaders.userLoader.load(parent.authorId);
    }
  }
};

