// DataLoader solves N+1 problem by batching queries
const DataLoader = require('dataloader');

// Batch function: receives array of keys, returns array of results
const userLoader = new DataLoader(async (userIds) => {
    const users = await db.users.findByIds(userIds);
    // MUST return in same order as input keys
    return userIds.map(id => users.find(u => u.id === id) || null);
});

const resolvers = {
    Post: {
        // Instead of N queries (one per post), DataLoader batches into 1
        author: async (post) => {
            return userLoader.load(post.authorId);
        }
    },
    Query: {
        posts: async (_, { first, after }) => {
            // Cursor-based pagination
            const query = db.posts.orderBy('createdAt', 'desc');
            if (after) {
                const cursor = decodeCursor(after);
                query.where('createdAt', '<', cursor);
            }
            const posts = await query.limit(first + 1);
            const hasNext = posts.length > first;
            return {
                edges: posts.slice(0, first).map(p => ({
                    node: p,
                    cursor: encodeCursor(p.createdAt)
                })),
                pageInfo: { hasNextPage: hasNext }
            };
        }
    }
};
